{id:270,title:"The Vanishing Half",author:"Brit Bennett",year:2020,genres:["Literary Fiction"],tags:["identity","race","family","class","secrets","contemporary"],blurb:"Identical twin sisters split apart when one decides to live the rest of her life passing as white."}
